@module util  src=util.lua  loc=649  sha=295cf55  mode=namespace  self=util

# Invariants & contracts
  @invariant  util.OPEN is the canonical "deliberately unbounded tail" marker for a note's endppqL. It is math.huge, so arithmetic on an open tail just works (inf + finite = inf, inf > finite = true) — callers no longer special-case the sentinel except to communicate intent. util.serialise/unserialise round-trip the non-finite floats via explicit inf/-inf/nan literals so the on-disk form is stable. Distinct from util.REMOVE: REMOVE clears a key on assign; OPEN is a persisted *value* of endppqL.  @ 42

# Module-level constants
  @const util = {}  @ 5
      @invariant  stateless module: pure helpers, no module-level mutable state beyond the REMOVE/OPEN sentinels  @ 3
      @invariant  util.REMOVE is the canonical delete marker honoured by assign and by mm/cm assignment APIs  @ 4
  @const BASE36 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ'  @ 333
  @const BASE62 = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRST...  @ 352
  @const LUA_KEYWORDS = {}  @ 551
  @const prettyEmit  @ 576   -- forward decl (mutual recursion with emitTable)

